//! Application services that orchestrate pure domain contracts over platform adapters.
//!
//! Services in this module are allowed to coordinate filesystem, registry,
//! process, and background seams through traits, but they should keep Slint and
//! user prompts out of the domain-facing behavior so workflows remain testable.

pub mod discovery;
pub mod overview;
pub mod overview_collector;
pub mod update;

/// No-op service-layer marker reserved for future orchestration state.
///
/// Constructing this marker performs no filesystem, registry, process, network,
/// scanner, settings, or UI work.
#[derive(Debug, Default, Clone, Copy)]
pub struct ServiceLayer;

import { Button, GroupBox, ScrollView } from "std-widgets.slint";

export struct OverviewUiRow {
    label: string,
    value: string,
    detail: string,
    severity: string,
}

component SeverityText inherits Text {
    in property <string> severity: "neutral";

    color: root.severity == "good" ? #8fdc8f :
        root.severity == "warning" ? #ffd166 :
        root.severity == "error" ? #ff7b7b :
        root.severity == "info" ? #8ecbff :
        root.severity == "unknown" ? #a8a8a8 :
        #d8d8d8;
}

component OverviewRows inherits Rectangle {
    in property <[OverviewUiRow]> rows;
    in property <length> label-width: 118px;

    min-height: 28px;

    VerticalLayout {
        padding: 0px;
        spacing: 5px;
        alignment: start;

        for row in root.rows: VerticalLayout {
            padding: 0px;
            spacing: 1px;
            alignment: start;

            HorizontalLayout {
                spacing: 6px;
                alignment: start;

                Text {
                    text: row.label + ":";
                    width: root.label-width;
                    font-size: 13px;
                    color: #f3f3f3;
                    horizontal-alignment: right;
                    vertical-alignment: top;
                }

                SeverityText {
                    text: row.value;
                    severity: row.severity;
                    font-size: 13px;
                    wrap: word-wrap;
                }
            }

            if row.detail != "": HorizontalLayout {
                spacing: 6px;
                alignment: start;

                Text {
                    text: "";
                    width: root.label-width;
                    font-size: 11px;
                }

                Text {
                    text: row.detail;
                    color: #a8a8a8;
                    font-size: 11px;
                    wrap: word-wrap;
                }
            }
        }
    }
}

component OverviewPanel inherits Rectangle {
    in property <string> title;
    in property <[OverviewUiRow]> rows;
    in property <length> label-width: 118px;
    in property <string> action-label: "";
    in property <bool> action-enabled: false;
    in property <string> action-status: "";

    callback action-requested();

    min-height: 188px;

    GroupBox {
        title: root.title;

        VerticalLayout {
            padding: 8px;
            spacing: 8px;
            alignment: start;

            OverviewRows {
                rows: root.rows;
                label-width: root.label-width;
            }

            if root.action-label != "": Rectangle {
                height: 1px;
                background: #3a3a3a;
            }

            if root.action-label != "": HorizontalLayout {
                spacing: 8px;
                alignment: start;

                Button {
                    text: root.action-label;
                    enabled: root.action-enabled;
                    clicked => {
                        root.action-requested();
                    }
                }

                Text {
                    text: root.action-status;
                    color: root.action-enabled ? #c8c8c8 : #a8a8a8;
                    font-size: 12px;
                    vertical-alignment: center;
                    wrap: word-wrap;
                }
            }
        }
    }
}

